class ContextFilter(logging.Filter):
    """Filter that adds contextual information to log records."""

    def __init__(self, app_name="application", environment="production"):
        super().__init__()
        self.app_name = app_name
        self.environment = environment

    def filter(self, record):
        record.app_name = self.app_name
        record.environment = self.environment
        if not hasattr(record, "request_id"):
            record.request_id = "N/A"
        if not hasattr(record, "user_id"):
            record.user_id = "anonymous"
        return True


class SensitiveDataFilter(logging.Filter):
    """Filter that redacts sensitive information from log messages."""

    SENSITIVE_PATTERNS = [
        "password",
        "secret",
        "token",
        "api_key",
        "authorization",
        "credit_card",
        "ssn",
    ]

    def filter(self, record):
        message = record.getMessage()
        for pattern in self.SENSITIVE_PATTERNS:
            if pattern.lower() in message.lower():
                record.msg = self._redact(record.msg, pattern)
        return True

    @staticmethod
    def _redact(message, pattern):
        import re
        regex = re.compile(
            rf'({re.escape(pattern)}[\s]*[=:]\s*)[^\s,;\"\']+',
            re.IGNORECASE,
        )
        return regex.sub(r"\1[REDACTED]", str(message))


def setup_logging(
    app_name="application",
    environment="production",
    log_level=None,
    config_override=None,
):
    """
    Initialize the logging configuration for the application.

    Args:
        app_name: Name of the application for contextual logging.
        environment: Deployment environment (production, staging, development).
        log_level: Override the default log level.
        config_override: Dictionary to override specific config values.
    """
    config = LOGGING_CONFIG.copy()

    if config_override:
        config.update(config_override)

    if log_level:
        for logger_name, logger_config in config.get("loggers", {}).items():
            logger_config["level"] = log_level

    logging.config.dictConfig(config)

    # Apply custom filters to all handlers
    context_filter = ContextFilter(app_name=app_name, environment=environment)
    sensitive_filter = SensitiveDataFilter()

    for handler in logging.root.handlers:
        handler.addFilter(context_filter)
        handler.addFilter(sensitive_filter)

    for logger_name in config.get("loggers", {}):
        logger = logging.getLogger(logger_name)
        for handler in logger.handlers:
            handler.addFilter(context_filter)
            handler.addFilter(sensitive_filter)

    startup_logger = logging.getLogger("application")
    startup_logger.info(
        "Logging initialized for %s in %s environment",
        app_name,
        environment,
    )

    return startup_logger


def get_logger(name, request_id=None, user_id=None):
    """
    Get a logger instance with optional contextual information.

    Args:
        name: Logger name (will be prefixed with 'application.' if not already).
        request_id: Optional request ID for request tracing.
        user_id: Optional user ID for user tracking.

    Returns:
        logging.Logger: Configured logger instance.
    """
    if not name.startswith("application."):
        name = f"application.{name}"

    logger = logging.getLogger(name)

    if request_id or user_id:
        adapter_extra = {}
        if request_id:
            adapter_extra["request_id"] = request_id
        if user_id:
            adapter_extra["user_id"] = user_id
        return logging.LoggerAdapter(logger, adapter_extra)

    return logger


# Health check function for monitoring
def check_logging_health():
    """
    Verify that all log files are writable and handlers are functional.

    Returns:
        dict: Health status of each log handler.
    """
    health_status = {}
    config = LOGGING_CONFIG

    for handler_name, handler_config in config.get("handlers", {}).items():
        if "filename" in handler_config:
            filepath = handler_config["filename"]
            try:
                directory = os.path.dirname(filepath)
                dir_exists = os.path.isdir(directory)
                dir_writable = os.access(directory, os.W_OK) if dir_exists else False

                if os.path.exists(filepath):
                    file_writable = os.access(filepath, os.W_OK)
                    file_size = os.path.getsize(filepath)
                else:
                    file_writable = dir_writable
                    file_size = 0

                health_status[handler_name] = {
                    "status": "healthy" if (dir_writable and file_writable) else "unhealthy",
                    "filepath": filepath,
                    "directory_exists": dir_exists,
                    "directory_writable": dir_writable,
                    "file_writable": file_writable,
                    "file_size_bytes": file_size,
                }
            except Exception as e:
                health_status[handler_name] = {
                    "status": "error",
                    "filepath": filepath,
                    "error": str(e),
                }

    return health_status


